package main
import "fmt"

// A function that catches the panic
func handlePanic() {
    if r := recover(); r != nil {
        fmt.Println("Phew! We recovered from a panic! Reazon:", r)
    }
}

func dangerousTask() {
    // Always DEFER the recovery function
    defer handlePanic()

    fmt.Println("About to panic...")
    // Trigger a panic manually!
    panic("Engine failure!")
}

func main() {
    dangerousTask()
    fmt.Println("Program continues normally because we recovered.")
}
